package github.chains;

import spoon.processing.AbstractProcessor;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.code.CtStatement;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;
import java.util.List;

public class LiquibaseExecutorServiceFixer extends AbstractProcessor<CtInvocation> {
    @Override
    public void process(CtInvocation invocation) {
        // Check if this is the pattern we want to fix:
        // ExecutorService.getInstance().getExecutor(database).execute(statement)

        // Check if the invocation is on getExecutor method
        if (invocation.getExecutable().getSimpleName().equals("getExecutor")) {
            // Get the target of the invocation (should be ExecutorService.getInstance())
            CtExpression target = invocation.getTarget();
            if (target != null && target.getType().getSimpleName().equals("ExecutorService")) {
                // Check if there's a subsequent execute call
                if (target.getParent() instanceof CtInvocation) {
                    CtInvocation parentInvocation = (CtInvocation) target.getParent();
                    if (parentInvocation.getExecutable().getSimpleName().equals("execute")) {
                        // This is the pattern we want to fix
                        // We need to replace the entire chain with the new API
                        fixExecutorServiceCall(invocation, parentInvocation);
                    }
                }
            }
        }
    }

    private void fixExecutorServiceCall(CtInvocation getExecutorInvocation, CtInvocation executeInvocation) {
        // Create the replacement call: ExecutorService.getInstance().execute(database, statement)
        Factory factory = getExecutorInvocation.getFactory();

        // Get the database and statement arguments
        CtExpression databaseArg = getExecutorInvocation.getArguments().get(0);
        CtExpression statementArg = executeInvocation.getArguments().get(0);

        // Create the new invocation: ExecutorService.getInstance().execute(database, statement)
        CtInvocation newInvocation = factory.createInvocation(
            factory.createTypeAccess(factory.Type().createReference("liquibase.executor.ExecutorService")),
            factory.createExecutableReference()
                .setSimpleName("execute")
                .setType(factory.Type().createReference("void")),
            factory.createLiteral("execute"), // method name
            databaseArg,
            statementArg
        );

        // Replace the old pattern with the new one
        executeInvocation.replace(newInvocation);
    }
}

